import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface EstimatedFare {
  currency: string;
  amount: number;
}

interface Driver {
  name: string;
  rating: number;
  vehicle: string;
  licensePlate: string;
}

interface RideShareData {
  estimatedFare: EstimatedFare;
  estimatedArrivalTime: string;
  driver: Driver;
}

export default function Widget() {
  const rideShareData = response.data as RideShareData;
  const { estimatedFare, estimatedArrivalTime, driver } = rideShareData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: theme === 'dark' ? '#1E293B' : '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              RideShare Now
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Arrival: {estimatedArrivalTime}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Driver
            </Typography>
            <Typography variant="h5" fontWeight={500} sx={{ color: '#F8FAFC' }}>
              {driver.name}
            </Typography>
            <Stack direction="row" spacing={1} alignItems="center">
              <Chip
                label={`Rating: ${driver.rating.toFixed(1)}`}
                sx={{ fontSize: '10px', bgcolor: accentColor, color: '#000000' }}
              />
              <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                {driver.vehicle} - {driver.licensePlate}
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Fare
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: primaryColor }}>
              {estimatedFare.currency} {estimatedFare.amount.toFixed(2)}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5} alignItems="center">
            <Info sx={{ fontSize: 16, color: accentColor }} />
            <Typography variant="caption" sx={{ color: '#94A3B8' }}>
              Fares may vary slightly based on traffic conditions.
            </Typography>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
